from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
import secrets
import time
import redis
import json
from datetime import datetime, timedelta
import logging

app = Flask(__name__)
app.config['SECRET_KEY'] = secrets.token_hex(32)

# Rate limiting
limiter = Limiter(
    app,
    key_func=get_remote_address,
    default_limits=["200 per hour"]
)

# Redis connection for token storage
redis_client = redis.StrictRedis(host='localhost', port=6379, db=0, decode_responses=True)

# In-memory storage for rate limiting (in production use Redis)
login_attempts = {}

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class User:
    def __init__(self, username, password_hash, email):
        self.username = username
        self.password_hash = password_hash
        self.email = email
        self.created_at = datetime.utcnow()

# Mock database
users_db = {}

def generate_token():
    return secrets.token_urlsafe(32)

def is_valid_token(token):
    try:
        token_data = redis_client.get(f"token:{token}")
        if token_data:
            return json.loads(token_data)
        return None
    except Exception:
        return None

def store_token(token, user_data):
    try:
        redis_client.setex(
            f"token:{token}",
            3600,  # 1 hour expiry
            json.dumps(user_data)
        )
        return True
    except Exception:
        return False

def delete_token(token):
    try:
        redis_client.delete(f"token:{token}")
        return True
    except Exception:
        return False

def rate_limit_check(identifier, max_attempts=5, window=300):
    now = time.time()
    if identifier not in login_attempts:
        login_attempts[identifier] = []
    
    # Remove old attempts
    login_attempts[identifier] = [
        attempt for attempt in login_attempts[identifier]
        if now - attempt < window
    ]
    
    if len(login_attempts[identifier]) >= max_attempts:
        return False
    
    login_attempts[identifier].append(now)
    return True

@app.route('/register', methods=['POST'])
@limiter.limit("5 per minute")
def register():
    try:
        data = request.get_json()
        username = data.get('username')
        password = data.get('password')
        email = data.get('email')
        
        if not all([username, password, email]):
            return jsonify({'error': 'Missing required fields'}), 400
        
        if username in users_db:
            return jsonify({'error': 'Username already exists'}), 409
        
        if not rate_limit_check(username):
            return jsonify({'error': 'Too many attempts'}), 429
        
        password_hash = generate_password_hash(password)
        user = User(username, password_hash, email)
        users_db[username] = user
        
        logger.info(f"User registered: {username}")
        return jsonify({'message': 'User registered successfully'}), 201
        
    except Exception as e:
        logger.error(f"Registration error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/login', methods=['POST'])
@limiter.limit("10 per minute")
def login():
    try:
        data = request.get_json()
        username = data.get('username')
        password = data.get('password')
        
        if not all([username, password]):
            return jsonify({'error': 'Missing credentials'}), 400
        
        if not rate_limit_check(username):
            return jsonify({'error': 'Too many login attempts'}), 429
        
        user = users_db.get(username)
        if not user or not check_password_hash(user.password_hash, password):
            logger.warning(f"Failed login attempt for: {username}")
            return jsonify({'error': 'Invalid credentials'}), 401
        
        # Generate token
        token = generate_token()
        user_data = {
            'username': user.username,
            'email': user.email,
            'created_at': datetime.utcnow().isoformat()
        }
        
        if store_token(token, user_data):
            logger.info(f"User logged in: {username}")
            return jsonify({
                'token': token,
                'user': {
                    'username': user.username,
                    'email': user.email
                }
            }), 200
        else:
            return jsonify({'error': 'Login failed'}), 500
            
    except Exception as e:
        logger.error(f"Login error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/logout', methods=['POST'])
@limiter.limit("20 per minute")
def logout():
    try:
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Invalid token'}), 401
        
        token = auth_header.split(' ')[1]
        if delete_token(token):
            return jsonify({'message': 'Logged out successfully'}), 200
        else:
            return jsonify({'error': 'Logout failed'}), 500
            
    except Exception as e:
        logger.error(f"Logout error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/profile', methods=['GET'])
@limiter.limit("30 per minute")
def profile():
    try:
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authorization required'}), 401
        
        token = auth_header.split(' ')[1]
        user_data = is_valid_token(token)
        
        if not user_data:
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        return jsonify({
            'user': {
                'username': user_data['username'],
                'email': user_data['email']
            }
        }), 200
        
    except Exception as e:
        logger.error(f"Profile error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/protected', methods=['GET'])
@limiter.limit("100 per minute")
def protected():
    try:
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authorization required'}), 401
        
        token = auth_header.split(' ')[1]
        user_data = is_valid_token(token)
        
        if not user_data:
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        return jsonify({
            'message': 'This is a protected endpoint',
            'user': user_data['username']
        }), 200
        
    except Exception as e:
        logger.error(f"Protected endpoint error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

